export const STORY_SECTION_KEYS = [
    'story',
    'acceptanceCriteria',
    'storyPoints',
    'priority',
    'blockers',
    'dependencies',
    'designNotes',
] as const;

export type StorySectionKey = typeof STORY_SECTION_KEYS[number];

export const STORY_SECTION_HEADINGS: Record<StorySectionKey, string> = {
    story: 'Story',
    acceptanceCriteria: 'Acceptance Criteria',
    storyPoints: 'Story Points',
    priority: 'Priority',
    blockers: 'Blockers',
    dependencies: 'Dependencies',
    designNotes: 'Design Notes',
};

export const STORY_SECTION_HEADING_TO_KEY: Record<string, StorySectionKey> = {
    'Story': 'story',
    'Acceptance Criteria': 'acceptanceCriteria',
    // Tolerate the legacy template typo. Files written before story 075 may still use this spelling.
    'Aceptance Criteria': 'acceptanceCriteria',
    'Story Points': 'storyPoints',
    'Priority': 'priority',
    'Blockers': 'blockers',
    'Dependencies': 'dependencies',
    'Design Notes': 'designNotes',
};

export interface Story {
    id: string;
    title: string;
    /**
     * Verbatim text from the start of the file up to (but not including) the first `## ` heading.
     * Preserved so parse → serialize → parse round-trips on stories with non-canonical preambles
     * (e.g. `# Subtask: ...` files). On title changes, `setStoryTitle` rewrites only the matching
     * `^# ` line inside this string. Authors generally don't see this field; PWA reads `title`.
     */
    rawPreamble: string;
    sections: Partial<Record<StorySectionKey, string>>;
    /**
     * Headings outside the template, preserved verbatim so parse → serialize → parse round-trips.
     * Keys are the literal heading text; values are the section body (without surrounding newlines).
     * Order is preserved by insertion order.
     */
    extraSections: Record<string, string>;
}

export const SCRUMBOARD_SECTION_KINDS = ['now', 'up-next', 'backlog', 'parked', 'recently-done', 'other'] as const;
export type ScrumboardSectionKind = typeof SCRUMBOARD_SECTION_KINDS[number];

/**
 * A single story entry parsed out of a board section. The board is hand-edited prose, so this is
 * a *best-effort* structural read used for status derivation only — display renders the verbatim
 * section body, never these fields.
 */
export interface ScrumboardItem {
    /** Story id (`\d{3}[a-z]?`), or '' for entries with no numeric id ("OFF contribution …"). */
    id: string;
    /** Plain-text description with markdown emphasis/strikethrough markers stripped. */
    title: string;
    /** True when the entry was struck through / declined (`~~ … ~~`). */
    superseded: boolean;
}

/** One `## ` section of the board, in document order. */
export interface ParsedScrumboardSection {
    kind: ScrumboardSectionKind;
    /** Verbatim heading text after `## ` (e.g. 'Up Next', 'Recently Done (last ~10 …)'). */
    heading: string;
    /** Verbatim markdown body under the heading (blank edges trimmed) — the display source. */
    body: string;
    /** Story entries found anywhere in the section (flattened across `### area` subsections). */
    items: ScrumboardItem[];
}

/**
 * Tolerant, read-only model of `docs/scrumboard.md` in its live Now / Up Next / area-Backlog /
 * Parked / Recently Done shape. There is no serializer — the file is mutated only by the minimal
 * `addStoryToScrumboard` line splice, so the hand-edited prose is never round-tripped lossily.
 */
export interface Scrumboard {
    /** Verbatim text before the first `## ` heading (title + intro blockquote). */
    preamble: string;
    sections: ParsedScrumboardSection[];
    /** Story ids called out in **bold** in the `Now` section — the in-progress signal. */
    inProgressIds: string[];
    /** `### area` headings under `## Backlog` — the valid create-story destinations. */
    backlogAreas: string[];
}

/** Where a freshly-created story's bullet is appended on the board. */
export type ScrumboardDestination =
    | { section: 'up-next' }
    | { section: 'backlog'; area: string };

export interface PatchStoryBody {
    title?: string;
    sections?: Partial<Record<StorySectionKey, string>>;
}

export interface CreateStoryBody {
    title: string;
    sections?: Partial<Record<StorySectionKey, string>>;
    /** Board destination for the new story bullet. Defaults to the first backlog area. */
    destination?: ScrumboardDestination;
}

export interface CreateStoryResponse {
    id: string;
    canonicalMarkdown: string;
}

export interface StoryResponse {
    id: string;
    story: Story;
    canonicalMarkdown: string;
}

/**
 * Shape of a draft returned by the AI structuring endpoint. Same envelope as `CreateStoryBody`
 * (`title` + optional `sections`) so the existing create-story validator gates AI output and
 * human-typed POSTs with one rule.
 */
export interface StoryDraft {
    title: string;
    sections: Partial<Record<StorySectionKey, string>>;
}

export interface StoryDraftRequestBody {
    notes: string;
}

export interface StoryDraftResponse {
    draft: StoryDraft;
}
