/**
 * Lean wrapper around the Web Speech API's `SpeechRecognition`. Targets Chromium only — no
 * webkit-prefix fallback. Global type declarations come from `@types/dom-speech-recognition`
 * (referenced via `tsconfig.app.json` "types"), so this file is just the behavior.
 *
 * Recognition runs through Chrome's default (cloud) path. Story 131 originally set
 * `processLocally: true` to keep audio on-device, but Chrome Android and snap-Chromium on
 * Ubuntu both refuse `language-not-supported` — see design_log.md #137 for the revert
 * rationale. The audio stream therefore reaches Google's recognition service; only the
 * resulting transcript is exposed to callers.
 *
 * MDN: https://developer.mozilla.org/en-US/docs/Web/API/SpeechRecognition
 */

import { createComponentLogger } from './component-logger.js';

const log = createComponentLogger('speech-dictation');

export interface SpeechDictationOptions {
    lang?: string;
    oninterim?: (text: string) => void;
    onfinal?: (text: string) => void;
    onerror?: (error: { code: string; message: string }) => void;
    /**
     * Fires whenever the underlying recognition session ends — user stop, error, or browser-
     * driven silence timeout. The component uses this to keep its mic button state synced.
     */
    onend?: () => void;
}

/**
 * Promote bare BCP-47 codes (`en`, `nl`) to a region-bearing form (`en-US`, `nl-NL`). Anything
 * already tagged with a region passes through. Falls back to `en-US` when nothing is supplied.
 * Cloud recognition is happy with either form but our `<html lang="en">` would otherwise leak
 * a bare code; keeping the helper makes the wire value predictable in logs.
 */
export function normalizeLang(input: string | undefined): string {
    const candidate = (input ?? document.documentElement.lang ?? '').trim();
    if (!candidate) return 'en-US';
    if (candidate.includes('-')) return candidate;
    const defaults: Record<string, string> = {
        en: 'en-US', nl: 'nl-NL', de: 'de-DE', fr: 'fr-FR', es: 'es-ES', it: 'it-IT', pt: 'pt-PT', ja: 'ja-JP',
    };
    return defaults[candidate.toLowerCase()] ?? `${candidate}-US`;
}

export function isSpeechRecognitionSupported(): boolean {
    return typeof SpeechRecognition !== 'undefined';
}

/**
 * Maps standard Web Speech API error codes to friendly, actionable messages.
 * Centralized here to keep all speech error mappings consistent.
 */
export function getFriendlyErrorMessage(code: string, rawMessage?: string): string {
    switch (code) {
        case 'language-not-supported':
            return 'Language pack not installed. Please install the language pack in your device settings.';
        case 'not-allowed':
        case 'service-not-allowed':
            return 'Mic blocked — grant microphone permission in the browser, then click again.';
        case 'network':
            return 'Dictation needs a connection — check your network and try again';
        case 'no-speech':
            return 'No speech detected — try speaking sooner after pressing the mic.';
        case 'audio-capture':
            return 'No microphone available. Connect a mic and reload.';
        case 'not-supported':
            return 'Voice recognition is not available in this browser.';
        default:
            return `Dictation error (${code}): ${rawMessage || code}`;
    }
}

export class SpeechDictation {
    private recognition: SpeechRecognition | null = null;
    private listening = false;
    /**
     * Highest `event.results` index whose `isFinal=true` transcript has already been
     * dispatched to `onfinal` in the current session. Reset to `-1` on every `start()`.
     * Why: Chrome (notably the Android cloud path — design_log #137) sometimes emits a
     * follow-up `onresult` whose iteration window `[resultIndex, results.length)` still
     * covers a previously-finalized result, which would otherwise re-fire `onfinal` and
     * make the consumer append the same chunk twice. See story 151.
     */
    private lastFinalIndex = -1;

    constructor(private readonly options: SpeechDictationOptions = {}) {}

    get isListening(): boolean { return this.listening; }

    start(): void {
        if (this.listening) return;
        if (typeof SpeechRecognition === 'undefined') {
            this.options.onerror?.({ code: 'not-supported', message: 'SpeechRecognition unavailable in this browser' });
            return;
        }

        const lang = normalizeLang(this.options.lang);
        const recognition = new SpeechRecognition();
        recognition.lang = lang;
        recognition.continuous = true;
        recognition.interimResults = true;
        this.lastFinalIndex = -1;

        recognition.onresult = (event: SpeechRecognitionEvent) => {
            for (let i = event.resultIndex; i < event.results.length; i++) {
                const result = event.results[i];
                const transcript = result[0]?.transcript ?? '';
                if (result.isFinal) {
                    if (i <= this.lastFinalIndex) continue;
                    this.lastFinalIndex = i;
                    this.options.onfinal?.(transcript);
                } else {
                    this.options.oninterim?.(transcript);
                }
            }
        };
        recognition.onerror = (event) => {
            log.warn('recognition error', { code: event.error, message: event.message });
            this.options.onerror?.({ code: event.error, message: event.message ?? event.error });
        };
        recognition.onend = () => {
            log.info('recognition ended');
            this.listening = false;
            this.options.onend?.();
        };

        this.recognition = recognition;
        this.listening = true;
        recognition.start();
        log.info('started', { lang });
    }

    stop(): void {
        this.recognition?.stop();
    }

    abort(): void {
        this.recognition?.abort();
        this.listening = false;
    }
}
